def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 7) / ((a + b) * 1.1 + 1)
                    priority += val * np.sin(ratio * b / (a + 1)) * np.cos(a * b)
            priority += np.exp(ratio - 8) * (np.sin(ratio * 1.3) ** 2.2)
            if ratio > 12:
                priority += np.log(ratio) * 15
            else:
                priority -= np.sqrt(ratio) * 7
        elif 5 < ratio <= 8:
            s = 0
            for m in range(1, 15):
                s += ((ratio - 5) ** m) * np.sin(ratio * m) / (m + 0.7)
            priority = np.tanh(s) * 12 + np.exp(-(ratio - 6)) * 8
            for n in range(1, 6):
                priority += np.cos(n * ratio * i) / (n + 1)
            if bin_cap < item * 1.3:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio) * 2.5
        elif 2 < ratio <= 5:
            s1, s2 = 0, 0
            for x in range(1, 20):
                s1 += ((ratio - 2) ** x) / (x * 2.3) * np.cos(x * ratio)
                s2 += ((5 - ratio) ** x) / (x * 1.1) * np.sin(x * i)
            priority = s1 * np.cos(5 * ratio) + s2 * np.sin(3 * i) - np.log(ratio) * 5
            if i % 2 == 0:
                priority += np.sqrt(bin_cap) * 1.7
            else:
                priority -= np.sqrt(bin_cap) * 1.7
        elif 1 <= ratio <= 2:
            s = 0
            for y in range(1, 25):
                s += ((2 - ratio) ** y) / (y ** 2 + 0.4) * np.cos(y * item * 0.8)
            penalty = 0
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for z in range(1, 7):
                priority += np.sin(z * ratio * i) * ((ratio - 1) ** z) / (z * 1.3)
            if item % 2 == 0:
                priority *= 1.5
            else:
                priority /= 1.5
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 30):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.cos(n * bin_cap * 0.9)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.4) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for p in range(1, 20):
                s += ((0.5 - ratio) ** p) / (p * 5) * np.cos(p * ratio * 3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.8) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.3) * 5
            for q in range(1, 10):
                priority += ((0.5 - ratio) ** q) / (q * 7) * np.cos(item * q * 1.3)
        else:
            s = 0
            for r in range(1, 15):
                s += ((0.2 - ratio) ** r) / (r * 4) * np.sin(r * item * 0.7)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for sidx in range(1, 12):
                priority += ((0.2 - ratio) ** sidx) / (sidx * 8) * np.cos(item * sidx * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * item) % 3 == 0:
            for w in range(1, 4):
                priority += np.sin(w * ratio * i) * 0.2
        else:
            for w in range(1, 4):
                priority -= np.cos(w * ratio * i) * 0.2
        priorities[i] = priority
    return priorities
